def max_of_three(a, b, c):
    m = a
    if b > m:
        m = b
    if c > m:
        m = c
    return m

def dedupe(lst):
    seen = set()
    out = []
    for x in lst:
        if x not in seen:
            seen.add(x)
            out.append(x)
    return out

def second_largest(nums):
    u = sorted(set(nums), reverse=True)
    return u[1] if len(u) > 1 else None

def is_anagram(a, b):
    norm = lambda s: sorted(s.replace(' ', '').lower())
    return norm(a) == norm(b)

def rotate(lst, k):
    if not lst:
        return lst[:]
    k %= len(lst)
    return lst[-k:] + lst[:-k]
